var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_BOSUN","text":{"KOREA":"서둘러 장비를 점검해라!","JPN":"急いで装備を確認しろ！","ENG":"Check your gear, and move it!","TWN":"快去檢查裝備！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE"},{"id":"L4_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_BOSUN","text":{"KOREA":"크라켄은 순식간에 너희 몸뚱이를 낚아채 으스러뜨릴 거다!","JPN":"あっという間にクラーケンに捕まって全身を潰されるぞ！","ENG":"Kraken will snatch you up and crush you before you can blink!","TWN":"克拉肯要是揮起觸手，一瞬間就能捏碎你們！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"PIRATE_FRONTBAY_JACK_BOSUN","text":{"KOREA":"어설프게 싸울 거면 얌전히 대포알이나 장전해!","JPN":"中途半端に戦うぐらいなら、大人しく砲弾でも装填してろ！","ENG":"If you plan to fight half-heartedly, then sit quiet and load the cannons!","TWN":"要是戰鬥時只想敷衍，那就乖乖去裝填砲彈！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"선원들은 언제 모은 거야?","JPN":"あの船員たち、どうやって集めてきたの？","ENG":"When did you gather this crew?","TWN":"你什麼時候弄來這些船員的？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"이런 상황에 침착하게 대응하는 놈들을 찾는 게 쉬운 일은 아니었을 텐데.","JPN":"こんな状況でも冷静に対応できるやつらを探すのは簡単じゃないはずだけど。","ENG":"Finding people who can stay calm in this situation couldn't have been easy.","TWN":"很難找到能在這種情況還保持冷靜的人吧？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"보물사냥꾼 잭이라는 해적에게서 빌려왔단다.","JPN":"トレジャーハンター・ジャックっていう海賊に貸してもらったのよ。","ENG":"I borrowed them from a pirate called Treasure Hunter Jack.","TWN":"我跟寶藏獵人傑克借來的。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"지난 검은 범람 때 챙긴 보물들로 꽤 벌었다고 들었거든.","JPN":"前回の黒い氾濫で手に入れた宝でかなり儲けたって聞いてね。","ENG":"I heard he made quite a fortune off the treasures from the last Black Flood.","TWN":"聽說他靠上次黑色洪災時撿到的寶物賺了不少。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"관리국한테 뒤를 잡히기 싫으면 나에게 협력하라고 했지.","JPN":"管理局に尻尾を捕まれたくなかったら協力しなさいって言ったの。","ENG":"I told him if he didn't want the Administration sniffing around, he'd best cooperate with me.","TWN":"我只跟他說如果不想被管理局盯上，就乖乖配合我。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그, 그렇구나…….","JPN":"へ、へえ……","ENG":"R-right... I see...","TWN":"原、原來如此……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"크라켄과 싸워보는 건 처음이겠구나.","JPN":"クラーケンと戦うのは初めてよね。","ENG":"This must be your first time facing Kraken.","TWN":"這是妳第一次面對克拉肯吧？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"두렵지는 않니?","JPN":"怖くはない？","ENG":"Aren't you afraid?","TWN":"不害怕嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"에이버리는 저것보다 멀쩡했던 크라켄을 상대로도 이겨냈다며.","JPN":"エイバリーは本調子のクラーケンを相手にして勝ったんだろ。","ENG":"Avery beat Kraken when it was in better shape than that.","TWN":"聽說艾維利戰勝了更完整的克拉肯。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나도 대해적이 되기 위해선 크라켄을 쓰러뜨려야 해.","JPN":"あたしも大海賊になるならクラーケンを倒さなきゃならないんだ。","ENG":"If I want to become a great pirate, I have to defeat Kraken too.","TWN":"如果我想成為大海盜，就必須打倒它。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"두려워할 틈이 없다고.","JPN":"怖がってる暇なんかないよ。","ENG":"I don't have time to be afraid.","TWN":"我根本沒空害怕。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"두려워할 틈이 없다라…….","JPN":"怖がってる暇なんかない、か……","ENG":"Don't have time to be afraid...","TWN":"沒空害怕啊……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"PIRATE_NPC_FAST_FAST","text":{"KOREA":"선장님! 말씀하신 대로 마하 섬 아래쪽에 거대한 물체가 탐지되었습니다!","JPN":"船長！　おっしゃった通り、マッハ島の下に巨大な物体が探知されました！","ENG":"Captain! Just as you said, a massive object has been detected beneath Macha Island!","TWN":"船長！跟您說的一樣，在瑪查島下方偵測到巨大的物體！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_NPC_FAST_FAST","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"PIRATE_NPC_FAST_FAST","text":{"KOREA":"명령만 내려주십쇼!","JPN":"今すぐご命令を！","ENG":"Just say the word!","TWN":"只要您下令！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_NPC_FAST_FAST","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"녀석은 지금까지 우리가 만나왔던 괴물 중에서도 궤를 달리하는 존재다.","JPN":"やつは今まで遭遇してきた化け物の中でも桁外れの存在だ。","ENG":"That thing is unlike any monster we've ever faced.","TWN":"那傢伙跟我們之前遇到的怪物根本不是同一個層級。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"어쩌면… 우리 모두 죽음을 각오해야 할지도 몰라.","JPN":"もしかしたら……全員が死を覚悟しなければならないかもしれない。","ENG":"We might... all have to accept death.","TWN":"說不定……大家都得做好赴死的覺悟。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"……두렵지는 않나?","JPN":"……怖くはないか？","ENG":"...Aren't you afraid?","TWN":"……妳不害怕嗎？"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"선장, 우리는 두려워할 틈이 없어.","JPN":"船長、私たちに怖がってる暇なんかないよ。","ENG":"Captain, we don't have time to be afraid.","TWN":"船長，我們沒有害怕的時間。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"내일이라는 씨앗의 싹을 틔울 수만 있다면, 난 기꺼이 내 목숨을 거름으로 삼을 거야.","JPN":"明日という種を芽吹かせられるなら、この命が糧になったって構わないんだ。","ENG":"If we can sprout even the tiniest seed of tomorrow, I'll gladly let my life be the soil for it!","TWN":"只要能讓明天這顆種子萌芽，我願意把自己的性命化作養分。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"보니…….","JPN":"ボニー……","ENG":"Bonny...","TWN":"寶妮……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"나도 마찬가지란다, 에이버리.","JPN":"私も同じよ、エイバリー。","ENG":"The same goes for me, Avery.","TWN":"我也是啊，艾維利。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"앞으로 고향을 지켜나갈 아이들이 과거가 아닌, 미래를 꿈꿀 수 있게 된다면…….","JPN":"これから故郷を守っていく子どもたちが、過去じゃなく、未来を夢見ることができるなら……","ENG":"If the children who'll inherit our home can dream of tomorrow instead of clinging to the past...","TWN":"只要能讓守護家鄉的孩子們不再只能活在過去，而能懷抱未來……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"나는 기꺼이 검을 들고 돌격할 거란다.","JPN":"私はよろこんで剣を取り、飛び込むわ。","ENG":"I'll gladly raise my sword and charge.","TWN":"我也願意提起劍衝鋒陷陣。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"리드…….","JPN":"リード……","ENG":"Read...","TWN":"里德……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"PIRATE_NPC_NULL_ALL","text":{"KOREA":"저희도 마찬가지입니다!","JPN":"俺たちもです！","ENG":"Us too, Captain!","TWN":"我們也一樣。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_NPC_FAST_FAST","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"PIRATE_NPC_NULL_ALL","text":{"KOREA":"선장님께서 항상 꿈꾸셨던 그 미래.","JPN":"船長がいつも夢見てきたその未来。","ENG":"The future you always dreamed of.","TWN":"船長您一直夢想的那個未來，"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_NPC_FAST_FAST","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"PIRATE_NPC_NULL_ALL","text":{"KOREA":"함께 꿈꾸고 싶다구요!","JPN":"一緒に見たいんです！","ENG":"We want to dream it with you!","TWN":"我們也想懷抱同樣的夢想！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL2","face":"UNIT_IDLE"},"C":{"char_id":"PIRATE_NPC_FAST_FAST","face":"UNIT_IDLE"},"R":{"char_id":"PIRATE_FRONTBAY_NULL_SEVERAL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"마하 섬의 일출을 감상하라.","JPN":"マッハ島の日の出を見よ。","ENG":"Behold the sunrise of Macha Island.","TWN":"去看瑪查島的日出吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L6_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"왜냐하면 마하 섬의 일출은…….","JPN":"なぜならマッハ島の日の出は……","ENG":"Because the sunrise of Macha Island is...","TWN":"因為瑪查島的日出……"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L7_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"끝내주게 낭만적이니까.","JPN":"とてつもなくロマンチックだから。","ENG":"Is unbelievably romantic.","TWN":"浪漫得不得了。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L8_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"하핫, 다들 낭만 찾으러 갈 준비는 됐냐?!","JPN":"ハハッ。あんたたち、ロマンを追う準備はいい！？","ENG":"Haha! Everyone ready to chase the dream?!","TWN":"哈哈！大家準備好去尋找浪漫了嗎？！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L11_1","type":"dialog","speaker":"PIRATE_NPC_NULL_ALL","text":{"KOREA":"우오!!!","JPN":"おおー！！","ENG":"YEAHHH!!!","TWN":"嗚喔喔！！！"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_PRIDE"}}},"sfx":"FX_CUTSCEN_CROWD_CHEER"},{"id":"L13_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"저 애들은 이미 자기가 묻힐 자리를 찾은 것 같구나.","JPN":"みんな、すでに自分の死に場所を見つけたようね。","ENG":"Those kids look like they've already chosen where they want to be buried.","TWN":"看來這些孩子已經決定了要葬身何處了呢。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"선장. 명령을.","JPN":"船長、命令を。","ENG":"Captain. Your orders.","TWN":"船長，下令吧。"},"stage":{"bg":"CORRIDOR_04","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그래. 네 말이 맞구나.","JPN":"ええ、その通りね。","ENG":"Yes. You're right.","TWN":"沒錯，你說得對。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"조금이라도 빨리 크라켄을 쓰러뜨려야 마하 섬의 일출을 다시 볼 수 있을 테니까.","JPN":"マッハ島の日の出をもう一度見るには、少しでも早くクラーケンを倒さないと。","ENG":"The sooner we bring down Kraken, the sooner we can see the sunrise of Macha Island again.","TWN":"只有儘快打倒克拉肯，我們才能再次看到瑪查島的日出。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"마하 섬의 일출?","JPN":"マッハ島の日の出？","ENG":"The sunrise of Macha Island?","TWN":"瑪查島的日出？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"절벽 끝에서 바라보면 끝내준다는 그 일출 말하는 거야?","JPN":"崖っぷちからの眺めが最高だっていう、あの日の出のこと？","ENG":"The one they say looks incredible from the edge of the cliff?","TWN":"是站在懸崖邊看到的那個超美的日出？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"에이버리 해적단에 들어가기 위한 <color=#ffd34c>첫 번째 조건</color>이었지.","JPN":"エイバリー海賊団に入るための<color=#ffd34c>第1条件</color>だったわ。","ENG":"It was the <color=#ffd34c>first rule</color> to join the Avery Pirates.","TWN":"那可是加入艾維利海盜團的<color=#ffd34c>首要條件</color>。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"선장이 갈 곳 없던 나와 네 엄마를 처음 선원으로 받아준 날.","JPN":"船長が行き場のなかった私とあなたのお母さんを初めて船員として受け入れてくれた日。","ENG":"The day the captain first took in your mother and me, two strays with nowhere to go.","TWN":"船長收留無處可去的我和妳媽媽作為船員的第一天，"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그날 보여줬던 마하 섬의 일출을 잊을 수가 없단다.","JPN":"あの日見せてくれたマッハ島の日の出を、私は忘れられない。","ENG":"I can never forget the sunrise he showed us that day.","TWN":"我到現在都忘不了那天看到的瑪查島的日出。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그리고 그 조건 덕분에…….","JPN":"そしてその条件のおかげで……","ENG":"And because of that rule...","TWN":"而也多虧那個規則……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"우리 해적단은 과거에 머물러 있던 눈을 내일로 돌릴 수 있게 되었어.","JPN":"私たち海賊団は、過去に留まっていた視線を明日に向けることができたの。","ENG":"Our crew could finally turn their eyes from the past toward tomorrow.","TWN":"我們這群海盜才能把目光從過去轉向未來。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"나도 언젠가는… 그 일출을 볼 수 있을까?","JPN":"あたしもいつか……その日の出を見られるかな。","ENG":"Do you think... I'll get to see it too someday?","TWN":"我是不是有一天……也能看到那個日出？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그럼. 물론이지.","JPN":"ええ、もちろんよ。","ENG":"Of course.","TWN":"當然囉。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L33_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그것을 보지 않고서는 대해적을 논할 수 없는 거란다.","JPN":"あれを見ずに大海賊を目指すなんてあり得ないもの。","ENG":"You can't call yourself the Great Pirate until you've seen it.","TWN":"不看到那個，妳可稱不上大海盜。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"생각해보니 잊고 있었던 것 같아.","JPN":"そういえば忘れてたな。","ENG":"Now that I think about it, I forgot.","TWN":"仔細想想我好像都忘了。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"HARPOON_FRONTBAY_NULL_NULL","text":{"KOREA":"그런 낭만, 해적이라면 당연히 추구해야 하는 거였는데…….","JPN":"海賊なら、そういうロマンを追いかけるのが当たり前なのに……","ENG":"That's the kind of dream a pirate is supposed to chase...","TWN":"那種浪漫才是海盜本該追求的……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L36_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"후후, 요즘 해적들에게 남은 게 낭만 밖에 없기는 하지.","JPN":"ふふ。最近の海賊に残っているものといったら、ロマンしかないしね。","ENG":"Fufu, dream is about the only thing today's pirates have left.","TWN":"呵呵。現在的海盜，也就只剩浪漫了吧。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_FLASHBACK","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"HARPOON_FRONTBAY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L39_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"옛날 얘기하는 건 좋지만, 저희 진짜 위험하거든요?!","JPN":"思い出に浸るのもいいですが、今は本当に危険な状況ですからね！？","ENG":"Talking about the old days is nice, but we're in real danger right now!","TWN":"話說憶當年很好，但我們現在真的很危險耶？！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"좀만 더 서둘러주시겠어요?","JPN":"もう少し急いでいただけませんか？","ENG":"Could you please hurry a bit?!","TWN":"可以快一點嗎？"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"너도 퍽 재미가 없어졌구나, 벨라미.","JPN":"あなた可愛げがなくなったわね、ベラミー。","ENG":"You've become terribly dull, Bellamy.","TWN":"你也變無聊了，貝拉米。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"그 이름을 받을 때만해도 기쁜 표정을 숨기질 못했는데…….","JPN":"その名前をもらった時は、嬉しい顔も隠せないほどだったのに……","ENG":"When you first received that name, you couldn't hide how happy you were...","TWN":"當初拿到這名字時，還笑得合不攏嘴呢……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"그, 그게 중요한 게 아니잖아요!","JPN":"い、今は関係ないじゃないですか！","ENG":"Th-that's not the point right now!","TWN":"這、這不是重點啦！"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_DESPAIR"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"키이라. 그 총을 잘 간직하고 있거라.","JPN":"キーラ。その銃、大事に持っていなさい。","ENG":"Kiera. Keep that gun close.","TWN":"琪伊拉，好好保存把那把槍。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"}}}},{"id":"L47_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"네 엄마의 물건이기도 하지만,","JPN":"あなたのお母さんのものだからでもあるけど、","ENG":"It belonged to your mother, but also...","TWN":"那不只是妳母親的遺物，"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_IDLE"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"널 소중히 생각하는 사람들 모두가…….","JPN":"あなたを大切に思っている人全員が……","ENG":"Everyone who cares for you...","TWN":"也是所有珍惜妳的人……"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"R":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"좋아. 에이버리 해적단.","JPN":"よし、エイバリー海賊団。","ENG":"All right, Avery Pirates.","TWN":"好了，艾維利海盜團。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"오늘이 어쩌면 마지막 출항이 될 수도 있다.","JPN":"もしかすると今日の出航が最後になるかもしれない。","ENG":"Today may be our final voyage.","TWN":"今天或許是我們最後一次啟航。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"하지만 그게 너희들의 마지막이라는 소리가 아니야.","JPN":"だが、それがお前らの最後という意味ではない。","ENG":"But that doesn't mean it's your last.","TWN":"但這不代表你們的冒險會在這裡結束。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"선장은 배는 버려도 선원은 버리지 않는 법.","JPN":"船長は船は捨てても船員は捨てないもの。","ENG":"The captain may abandon the ship, but doesn't abandon the crew.","TWN":"船長可以捨棄船，但絕不會丟下船員。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"난 너희 모두를 살려서 고향으로 되돌려 보낼 것이다.","JPN":"私はお前らを全員、故郷に生還させる。","ENG":"I will bring every one of you home alive.","TWN":"我會讓你們全都平安回到故鄉。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"너희 모두가 내일을 꿈꿀 수 있도록.","JPN":"全員が明日を夢見ることができるように。","ENG":"So that you can all dream of tomorrow.","TWN":"讓你們依舊能夢想明天。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"나, 선장 에이버리는 너희를 이끌 것이다.","JPN":"船長エイバリーがお前らを導こう。","ENG":"I, Captain Avery, will lead you.","TWN":"我，船長艾維利將引領你們。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"자, 내가 이 함선 창고에서 가져온 보물들이다.","JPN":"見ろ、この艦船の倉庫から持ち出したお宝だ。","ENG":"Here. Treasures I found in this ship's storage.","TWN":"來，這些是我從艦船艙庫裡拿來的寶物。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L11_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"이건… 총?","JPN":"これは……銃？","ENG":"A gun...?","TWN":"這是……槍？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"미안하지만 선장, 나는 총보다는 검을 더 선호하는데…….","JPN":"船長、悪いけど私は銃より剣のほうが好みなのよ……","ENG":"Sorry, Captain, but I still prefer a sword...","TWN":"抱歉船長，我更習慣用劍……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"핫핫핫! 이건 살상용으로 만들어진 총이 아니야.","JPN":"ハハハ！　これは殺傷用に作られた銃じゃない。","ENG":"Gah hah hah! This isn't a weapon for killing.","TWN":"哈哈哈！這不是用來殺人的槍。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"<color=#ffd34c>벨라미</color>에게 물어보니 언제 어디서든 볼 수 있는 신호탄이라고 하더군.","JPN":"<color=#ffd34c>ベラミー</color>に聞いたが、いつ、どこにいても見ることのできる信号弾だそうだ。","ENG":"I asked <color=#ffd34c>Bellamy</color>, and she said it's a flare you can fire anywhere.","TWN":"我問過<color=#ffd34c>貝拉米</color>，他說這是隨時隨地都能看到的信號彈。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"BONNY_NPC_NULL_NULL","text":{"KOREA":"벨라미?","JPN":"ベラミー？","ENG":"Bellamy?","TWN":"貝拉米？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"BONNY_NPC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"SECRETARY_FRONTBAY_NULL_ADMIN","text":{"KOREA":"선장님이 저에게 붙여주신 새 이름이에요.","JPN":"船長につけていただいた新しい名前です。","ENG":"It's the new name the captain gave me.","TWN":"那是船長給我的新名字。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"모네카라는 이름은 자신과 같은 모델의 AI 오퍼레이터를 지칭하는 말이라고 해.","JPN":"モネカという名前は、彼女と同じモデルのAIオペレーターを指す名称だそうだ。","ENG":"Moneka was just a label for my AI operator model.","TWN":"因為莫奈卡只是指某型號的AI領航員嘛。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"에이버리 해적단의 항해사로 들어오기 위해선 따로 부를 멋진 이름이 필요한 법.","JPN":"エイバリー海賊団の航海士になるからには、自分だけの立派な名前が必要だろう。","ENG":"If I'm to serve as the navigator of Avery Pirates, I needed a proper pirate name.","TWN":"要加入艾維利海盜團，就必須有個夠海盜名字。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"해적다운 걸 추천해달라고 하기에 벨라미라는 멋진 이름을 지어줬지.","JPN":"海賊らしい名前を勧めてほしいと言われてな、ベラミーという立派な名前をつけてやったんだ。","ENG":"I asked for something bold, so he named me Bellamy.","TWN":"所以船長就幫我取了這個。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SECRETARY_FRONTBAY_NULL_ADMIN","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"……뭐, 해적다운 이름이라 나쁘지는 않구나.","JPN":"……まあ、確かに海賊らしいし悪くない名前ね。","ENG":"...Well, it does sound pirate-like.","TWN":"……嗯，確實挺像海盜的。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"READ_NPC_NULL_NULL","text":{"KOREA":"그럼 이 총만 가지고 있으면, 언제 어디서든 선장이 달려온다는 소리로 이해하면 되겠니?","JPN":"とにかく、この銃さえ持っていれば、いつどこにいても船長がすぐ駆けつけて来るという認識で問題ないかしら？","ENG":"So as long as we have this flare, we can assume the captain will come running anytime?","TWN":"那我可以想成只要我拿著這把槍，不管我在哪裡，船長都會趕來囉？"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"나뿐만이 아니야.","JPN":"私だけではない。","ENG":"Not just me.","TWN":"不只我。"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"JACK_FRONTBAY_NULL_AVERY","text":{"KOREA":"이 신호탄을 본 우리 모두가…….","JPN":"この信号弾を見た全員が……","ENG":"All of us who see this flare…","TWN":"所有看到這信號的人……"},"stage":{"bg":"CORRIDOR_04","bgm":"THEMA_SUMMER_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"READ_NPC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"READ_NPC_MARY_NULL","text":{"KOREA":"널 구하기 위해 달려올 테니까.","JPN":"あなたを助けるために、駆けつけて来るでしょうから。","ENG":"Will come running to help you.","TWN":"都會為了救妳衝過來。"},"stage":{"bg":"FRONTBAY_DECK_FOG","bgm":"THEMA_SUMMER_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"READ_NPC_MARY_NULL","face":"UNIT_PRIDE"},"R":null}}}]`);export{e as default};